-- Sauvegarde avant nettoyage doublons par nom

-- Structure table client
DROP TABLE IF EXISTS client_backup;
CREATE TABLE client_backup AS SELECT * FROM client; CREATE TABLE `client_backup` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `nom` varchar(100) NOT NULL,
  `telephone` varchar(100) NOT NULL,
  `adresse` varchar(200) NOT NULL,
  `ville` varchar(100) NOT NULL,
  `ip_router` varchar(50) DEFAULT NULL,
  `ip_antea` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_client_nom` (`nom`),
  KEY `idx_client_ville` (`ville`)
) ENGINE=InnoDB AUTO_INCREMENT=1754 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci

-- Données table client (1738 enregistrements)
DELETE FROM client_backup;


































